import{_ as a,y as r,a as p,o as l,ag as g,D as o,g as i,I as h}from"./chunks/framework.RVu0gECZ.js";const v=JSON.parse('{"title":"Xử lý báo giá","description":"","frontmatter":{},"headers":[],"relativePath":"b2b-ecommerce-platform/quotation-handling.md","filePath":"b2b-ecommerce-platform/quotation-handling.md","lastUpdated":1775325172000}'),c={name:"b2b-ecommerce-platform/quotation-handling.md"};function b(s,n,u,e,m,d){const t=r("ImagePopup");return l(),p("div",null,[n[0]||(n[0]=g('<h1 id="xu-ly-bao-gia" tabindex="-1">Xử lý báo giá <a class="header-anchor" href="#xu-ly-bao-gia" aria-label="Permalink to &quot;Xử lý báo giá&quot;">​</a></h1><p>Tính năng Xử lý báo giá giao diện người dùng cho phép người dùng công ty xem, theo dõi và quản lý tất cả các yêu cầu báo giá trực tiếp từ trang tổng quan của họ.</p><p>Người dùng có thể tạo, thương lượng và phản hồi các báo giá một cách liền mạch trực tiếp từ mặt tiền cửa hàng.</p><p><strong>Truy cập báo giá</strong></p><p>Đi tới <strong>Tài khoản của tôi → Hồ sơ → Báo giá</strong> từ cửa hàng của công ty.</p><h3 id="bao-gia-cua-toi" tabindex="-1">Báo giá của tôi <a class="header-anchor" href="#bao-gia-cua-toi" aria-label="Permalink to &quot;Báo giá của tôi&quot;">​</a></h3><p>Trang Báo giá của tôi hiển thị tất cả các yêu cầu báo giá do công ty gửi. Mỗi bản ghi bao gồm các chi tiết cần thiết để dễ dàng theo dõi và quản lý.</p><h4 id="chi-tiet-bao-gia-bao-gom" tabindex="-1">Chi tiết báo giá bao gồm: <a class="header-anchor" href="#chi-tiet-bao-gia-bao-gom" aria-label="Permalink to &quot;Chi tiết báo giá bao gồm:&quot;">​</a></h4><p><strong>1) ID:</strong> Mã định danh duy nhất cho mỗi báo giá.</p><p><strong>2) Tên báo giá:</strong> Tiêu đề được gán cho báo giá.</p><p><strong>3) Công ty:</strong> Tên công ty yêu cầu.</p><p><strong>4) Tổng cơ sở:</strong> Tổng số tiền trước khi thương lượng.</p><p><strong>5) Trạng thái:</strong> Giai đoạn hiện tại (Dự thảo, Mở, Đã chấp nhận, Bị từ chối).</p><p><strong>6) Được tạo vào lúc:</strong> Ngày và giờ tạo báo giá.</p><p><strong>7) Hành động:</strong> Sử dụng biểu tượng Xem để xem chi tiết báo giá đầy đủ và thực hiện các hành động tiếp theo.</p>',15)),o(t,{src:"/images/b2b-ecommerce-platform/1-Quotation.png",alt:"Super Admin Login"}),n[1]||(n[1]=i("h3",{id:"chi-tiet-bao-gia",tabindex:"-1"},[h("Chi tiết báo giá "),i("a",{class:"header-anchor",href:"#chi-tiet-bao-gia","aria-label":'Permalink to "Chi tiết báo giá"'},"​")],-1)),n[2]||(n[2]=i("p",null,"Bấm vào biểu tượng Xem bên dưới cột Hành động để mở thông tin báo giá chi tiết.",-1)),n[3]||(n[3]=i("p",null,"Phần này cung cấp chi tiết đầy đủ về báo giá đã chọn, bao gồm Thông tin báo giá, thông tin công ty, Hạng mục báo giá và Tin nhắn báo giá. Như thể hiện trong hình ảnh dưới đây.",-1)),o(t,{src:"/images/b2b-ecommerce-platform/2-quotation-details.png",alt:"Super Admin Login"}),n[4]||(n[4]=g('<h3 id="tin-nhan-bao-gia" tabindex="-1">Tin Nhắn Báo Giá <a class="header-anchor" href="#tin-nhan-bao-gia" aria-label="Permalink to &quot;Tin Nhắn Báo Giá&quot;">​</a></h3><p>Ở cuối trang chi tiết báo giá, người dùng có thể liên hệ trực tiếp với quản trị viên thông qua phần Tin nhắn báo giá.</p><p><strong>Cách gửi tin nhắn:</strong></p><ol><li><p>Nhấp vào nút Tin nhắn.</p></li><li><p>Nhập văn bản của bạn vào trường “Nhập tin nhắn của bạn vào đây…”.</p></li><li><p>Nhấp vào Gửi để gửi tin nhắn của bạn.</p></li></ol><p>Tất cả tin nhắn được hiển thị dưới chuỗi hội thoại với các chi tiết như tên người gửi, nội dung tin nhắn và dấu thời gian.</p>',5)),o(t,{src:"/images/b2b-ecommerce-platform/3-message.png",alt:"Super Admin Login"}),n[5]||(n[5]=g('<h3 id="trich-lai" tabindex="-1">Trích lại <a class="header-anchor" href="#trich-lai" aria-label="Permalink to &quot;Trích lại&quot;">​</a></h3><p>Nếu bạn muốn sửa lại hoặc gửi lại báo giá, hãy nhấp vào nút <strong>Trích lại</strong>.</p><p>Điều này cho phép bạn cập nhật giá, số lượng đã thương lượng hoặc đưa vào các nhận xét bổ sung trước khi gửi lại cho quản trị viên.</p><p><strong>Các trường bao gồm:</strong></p><p><strong>1) Tên:</strong> Tên sản phẩm trong báo giá.</p><p><strong>2) Giá thương lượng:</strong> Đã cập nhật giá thỏa thuận.</p><p><strong>3) Số lượng:</strong> Số lượng sản phẩm đã điều chỉnh.</p><p><strong>4) Trường tin nhắn (Bắt buộc):</strong> Thêm ghi chú trước khi gửi.</p><p>Nhấp vào <strong>Lưu</strong> để gửi báo giá đã sửa đổi để quản trị viên xem xét.</p>',9)),o(t,{src:"/images/b2b-ecommerce-platform/4-submit-your-quotation.png",alt:"Super Admin Login"}),n[6]||(n[6]=g('<h3 id="tu-choi-bao-gia" tabindex="-1">Từ chối báo giá <a class="header-anchor" href="#tu-choi-bao-gia" aria-label="Permalink to &quot;Từ chối báo giá&quot;">​</a></h3><p>Để từ chối báo giá, hãy nhấp vào nút <strong>Từ chối báo giá</strong>.</p><p>Một hộp thoại xuất hiện, cho phép bạn chỉ định lý do từ chối.</p><p><strong>Các bước:</strong></p><ol><li><p>Nhập tin nhắn của bạn hoặc lý do từ chối.</p></li><li><p>Nhấp vào Lưu để xác nhận.</p></li></ol><p>Sau khi lưu, trạng thái báo giá sẽ cập nhật tương ứng để phản ánh hành động được thực hiện.</p>',6)),o(t,{src:"/images/b2b-ecommerce-platform/5-reject-this-quotation.png",alt:"Super Admin Login"}),n[7]||(n[7]=g('<h3 id="quan-ly-bao-gia-cuoi-quan-tri-vien" tabindex="-1">Quản lý báo giá (Cuối quản trị viên) <a class="header-anchor" href="#quan-ly-bao-gia-cuoi-quan-tri-vien" aria-label="Permalink to &quot;Quản lý báo giá (Cuối quản trị viên)&quot;">​</a></h3><p>Tính năng Quản lý báo giá cho phép cả người dùng quản trị viên và công ty xem xét, đàm phán, phê duyệt hoặc từ chối báo giá một cách liền mạch.</p><p><strong>Truy cập báo giá</strong></p><p>Điều hướng đến <strong>Khách hàng → Báo giá</strong> từ bảng quản trị.</p><p>Phần này hiển thị tất cả các yêu cầu báo giá nhận được từ người dùng công ty để xem xét và hành động.</p><h3 id="danh-sach-bao-gia" tabindex="-1">Danh Sách Báo Giá <a class="header-anchor" href="#danh-sach-bao-gia" aria-label="Permalink to &quot;Danh Sách Báo Giá&quot;">​</a></h3><p>Trang Báo giá liệt kê tất cả các báo giá đã gửi cùng với các chi tiết chính để theo dõi, quản lý và đàm phán.</p><p>Quản trị viên cũng có thể sử dụng các tùy chọn như <strong>Xuất, Tạo báo giá, Tìm kiếm và Lọc</strong> để quản lý hồ sơ một cách hiệu quả.</p><p><strong>Chi tiết báo giá bao gồm:</strong></p><p><strong>1) ID báo giá / Tên báo giá:</strong> Mã định danh và tiêu đề duy nhất cho mỗi báo giá.</p><p><strong>2) Trạng thái:</strong> Giai đoạn hiện tại của báo giá (ví dụ: Mở, Được chấp nhận, Bị từ chối).</p><p><strong>3) Công ty/Khách hàng:</strong> Tên công ty và khách hàng kèm theo báo giá.</p><p><strong>4) Được tạo vào lúc:</strong> Ngày và giờ tạo báo giá.</p><p><strong>5) Tổng cơ sở / Tổng thương lượng:</strong> Số tiền ban đầu và số tiền đã thương lượng cho báo giá.</p><p><strong>6) Ngày hết hạn:</strong> Thời hạn hiệu lực của báo giá.</p><p><strong>7) Hạng mục báo giá:</strong> Các sản phẩm có trong báo giá.</p>',16)),o(t,{src:"/images/b2b-ecommerce-platform/6-quotation-admin.png",alt:"Super Admin Login"}),n[8]||(n[8]=i("p",null,[i("strong",null,"Chi tiết báo giá")],-1)),n[9]||(n[9]=i("p",null,[h("Nhấp vào biểu tượng "),i("strong",null,"Xem"),h(" bên cạnh mục báo giá để mở chế độ xem báo giá chi tiết.")],-1)),n[10]||(n[10]=i("p",null,"Phần này cung cấp thông tin đầy đủ về báo giá đã chọn, bao gồm Thông tin báo giá, thông tin công ty, Mục báo giá và Tin nhắn báo giá. Như thể hiện trong hình ảnh dưới đây.",-1)),o(t,{src:"/images/b2b-ecommerce-platform/7-quotation-information.png",alt:"Super Admin Login"}),n[11]||(n[11]=i("h3",{id:"tin-nhan-bao-gia-1",tabindex:"-1"},[h("Tin Nhắn Báo Giá "),i("a",{class:"header-anchor",href:"#tin-nhan-bao-gia-1","aria-label":'Permalink to "Tin Nhắn Báo Giá"'},"​")],-1)),n[12]||(n[12]=i("p",null,"Quản trị viên và người dùng công ty có thể trao đổi tin nhắn trực tiếp trong báo giá bằng phần Tin nhắn báo giá.",-1)),n[13]||(n[13]=i("p",null,[i("strong",null,"Cách gửi tin nhắn:")],-1)),n[14]||(n[14]=i("ol",null,[i("li",null,[i("p",null,"Nhấp vào nút Tin nhắn.")]),i("li",null,[i("p",null,"Nhập văn bản của bạn vào trường “Nhập tin nhắn của bạn vào đây…”.")]),i("li",null,[i("p",null,"Nhấp vào Gửi để gửi tin nhắn.")])],-1)),o(t,{src:"/images/b2b-ecommerce-platform/8-admin-quotation.png",alt:"Super Admin Login"}),n[15]||(n[15]=g('<h3 id="sgui-bao-gia" tabindex="-1">SGửi báo giá <a class="header-anchor" href="#sgui-bao-gia" aria-label="Permalink to &quot;SGửi báo giá&quot;">​</a></h3><p>Quản trị viên có thể sửa đổi và gửi lại báo giá với các điều khoản đàm phán được cập nhật.</p><p><strong>Các trường bao gồm:</strong></p><p><strong>1) Tên:</strong> Tên sản phẩm.</p><p><strong>2) Giá thương lượng:</strong> Giá báo đã sửa đổi sau khi thảo luận.</p><p><strong>3) Số lượng:</strong> Cập nhật số lượng sản phẩm.</p><p><strong>4) Trường thông báo (Bắt buộc):</strong> Thêm ghi chú thương lượng hoặc nhận xét trước khi gửi.</p><p>Nhấp vào <strong>Lưu</strong> để gửi báo giá cập nhật cho người dùng của công ty để xem xét.</p>',8)),o(t,{src:"/images/b2b-ecommerce-platform/9-send-message.png",alt:"Super Admin Login"}),n[16]||(n[16]=i("h3",{id:"achap-nhan-hoac-tu-choi-bao-gia",tabindex:"-1"},[h("AChấp nhận hoặc từ chối báo giá "),i("a",{class:"header-anchor",href:"#achap-nhan-hoac-tu-choi-bao-gia","aria-label":'Permalink to "AChấp nhận hoặc từ chối báo giá"'},"​")],-1)),n[17]||(n[17]=i("p",null,"Sau khi đàm phán hoàn tất, quản trị viên có thể hoàn tất báo giá.",-1)),n[18]||(n[18]=i("p",null,[i("strong",null,"Chấp nhận báo giá cuối cùng:")],-1)),n[19]||(n[19]=i("ol",null,[i("li",null,[i("p",null,"Nhấp vào nút Chấp nhận báo giá cuối cùng để phê duyệt.")]),i("li",null,[i("p",null,"Nhập tin nhắn và nhấp vào Lưu để xác nhận.")]),i("li",null,[i("p",null,"Trạng thái báo giá cập nhật thành Đã chấp nhận trên mặt tiền cửa hàng, cho phép công ty tiến hành mua hàng thông qua nút Thêm vào giỏ hàng.")])],-1)),o(t,{src:"/images/b2b-ecommerce-platform/10-accept-last-quotation.png",alt:"Super Admin Login"}),n[20]||(n[20]=i("p",null,[i("strong",null,"Lưu ý: Sau khi chấp nhận báo giá, bạn không thể sửa đổi số lượng sản phẩm. Để thực hiện thay đổi, bạn phải đưa ra báo giá mới.")],-1)),n[21]||(n[21]=i("h3",{id:"tu-choi-bao-gia-1",tabindex:"-1"},[h("Từ chối báo giá: "),i("a",{class:"header-anchor",href:"#tu-choi-bao-gia-1","aria-label":'Permalink to "Từ chối báo giá:"'},"​")],-1)),n[22]||(n[22]=i("ol",null,[i("li",null,[i("p",null,"Nhấp vào nút Từ chối Báo giá.")]),i("li",null,[i("p",null,"Nhập lý do từ chối vào trường tin nhắn.")]),i("li",null,[i("p",null,"Nhấp vào Lưu để hoàn tất hành động.")])],-1)),o(t,{src:"/images/b2b-ecommerce-platform/11-reject-quotation.png",alt:"Super Admin Login"}),n[23]||(n[23]=i("p",null,[i("strong",null,"Lưu ý: Sau khi hoàn thành báo giá (Được chấp nhận hoặc Từ chối), không được phép sửa đổi thêm sản phẩm hoặc giá cả.")],-1))])}const q=a(c,[["render",b]]);export{v as __pageData,q as default};
